// Expects: { productUuid, clientUuid, entries: [{ nodeIndex, confirmedName }] }
const body = $input.first().json.body ?? $input.first().json;

const productUuid = body.productUuid;
const clientUuid  = body.clientUuid   ?? 'b577b1c8-80bd-4dab-b1b1-b22f9de4671a';
const entries     = body.entries      ?? [];

if (!productUuid)      throw new Error('productUuid is required');
if (!entries.length)   throw new Error('entries array is required and must not be empty');

// Build a nodeIndex -> confirmedName map
const renameMap = {};
entries.forEach(e => {
  if (e.confirmedName && String(e.confirmedName).trim()) {
    renameMap[e.nodeIndex] = String(e.confirmedName).trim();
  }
});

return [{ json: { productUuid, clientUuid, renameMap, entryCount: entries.length } }];

const product = $input.first().json.response ?? $input.first().json;
const ids = $node['Extract Payload'].json;

const productName = product?.name ?? ids.productUuid;
const assetBlobId = product?.asset?.assetBlobId;

if (!assetBlobId) throw new Error(`No assetBlobId found for product ${ids.productUuid}. Ensure the product has a processed 3D asset.`);

return [{ json: { ...ids, productName, assetBlobId } }];

// Rewrite the GLB JSON chunk: apply confirmedName renames to matching node indexes.
// The binary chunk (geometry + textures) is preserved byte-for-byte.
const binaryData = $input.first().binary?.glbData;
if (!binaryData) throw new Error('No GLB binary data in glbData field');

const renameMap = $node['Extract Payload'].json.renameMap;
const ids       = $node['Resolve Blob'].json;

const buf = Buffer.from(binaryData.data, 'base64');

// Validate GLB magic
const magic = buf.readUInt32LE(0);
if (magic !== 0x46546C67) throw new Error('Not a valid GLB file');

const jsonChunkLength = buf.readUInt32LE(12);
const jsonChunkType   = buf.readUInt32LE(16);
if (jsonChunkType !== 0x4E4F534A) throw new Error('First GLB chunk is not JSON');

const jsonStr  = buf.slice(20, 20 + jsonChunkLength).toString('utf8').replace(/\0+$/, '');
const gltf     = JSON.parse(jsonStr);

// Apply renames
let renameCount = 0;
Object.entries(renameMap).forEach(([idxStr, newName]) => {
  const idx = parseInt(idxStr, 10);
  if (gltf.nodes[idx]) {
    gltf.nodes[idx].name = newName;
    renameCount++;
  }
});

// Serialize new JSON chunk — must be 4-byte aligned, padded with spaces
const newJsonStr = JSON.stringify(gltf);
const padLen     = (4 - (newJsonStr.length % 4)) % 4;
const paddedJson = newJsonStr + ' '.repeat(padLen);
const newJsonBuf = Buffer.from(paddedJson, 'utf8');

// Locate binary chunk (starts at byte 20 + jsonChunkLength, aligned)
const binaryChunkOffset = 20 + jsonChunkLength;
const hasBinaryChunk    = binaryChunkOffset < buf.length;
const binaryChunkBuf    = hasBinaryChunk ? buf.slice(binaryChunkOffset) : Buffer.alloc(0);

// Build new GLB
const newJsonChunkHeader = Buffer.alloc(8);
newJsonChunkHeader.writeUInt32LE(newJsonBuf.length, 0);
newJsonChunkHeader.writeUInt32LE(0x4E4F534A,        4); // JSON type

const newTotalLength = 12 + 8 + newJsonBuf.length + binaryChunkBuf.length;
const header = Buffer.alloc(12);
header.writeUInt32LE(0x46546C67, 0); // magic
header.writeUInt32LE(2,           4); // version
header.writeUInt32LE(newTotalLength, 8);

const newGlb = Buffer.concat([header, newJsonChunkHeader, newJsonBuf, binaryChunkBuf]);

const fileName = `${ids.productName.replace(/[^a-z0-9_-]/gi, '_')}_remapped.glb`;
const binary = {
  renamedGlb: await this.helpers.prepareBinaryData(
    newGlb,
    fileName,
    'model/gltf-binary'
  )
};

return [{
  json: { ...ids, renameCount, fileName },
  binary
}];

// Retrieve original mapping entries to merge confirmed names, then re-upload
const ids       = $node['Rewrite GLB'].json;
const renameMap = $node['Extract Payload'].json.renameMap;
const uploadResp = $input.first().json;

const finalMapping = {
  productUuid:   ids.productUuid,
  productName:   ids.productName,
  appliedAt:     new Date().toISOString(),
  renameCount:   ids.renameCount,
  uploadResponse: uploadResp,
  renames: Object.entries(renameMap).map(([idx, name]) => ({ nodeIndex: parseInt(idx, 10), confirmedName: name }))
};

const jsonStr  = JSON.stringify(finalMapping, null, 2);
const fileName = `scene-mapping-${ids.productUuid}.json`;

const binary = {
  mappingFile: await this.helpers.prepareBinaryData(
    Buffer.from(jsonStr, 'utf8'),
    fileName,
    'application/json'
  )
};

return [{ json: { ...ids, finalMapping, jsonStr, fileName }, binary }];
